CREATE VIEW `dwd_market_userrealtimerecord_view` (`dt` COMMENT "createtime 分区", `product_id` COMMENT "产品id", `id` COMMENT "id", `user_id` COMMENT "用户id", `parent_group_id` COMMENT "父人群包id", `group_id` COMMENT "人群包id", `group_type` COMMENT "0父 1子", `join_days` COMMENT "可参与天数", `can_repeated` COMMENT "可重复入包(0不可重复 、1 可重复)", `start_time` COMMENT "开始时间", `end_time` COMMENT "结束时间", `create_time` COMMENT "创建时间") AS (SELECT `ods`.`ods_tidb_readernovel_tidb_userrealtimerecord`.`dt`, `ods`.`ods_tidb_readernovel_tidb_userrealtimerecord`.`product_id`, min(`ods`.`ods_tidb_readernovel_tidb_userrealtimerecord`.`id`) AS `Id`, `ods`.`ods_tidb_readernovel_tidb_userrealtimerecord`.`Pid` AS `user_id`, `ods`.`ods_tidb_readernovel_tidb_userrealtimerecord`.`ParentGroupId` AS `parent_group_id`, `ods`.`ods_tidb_readernovel_tidb_userrealtimerecord`.`GroupId` AS `group_id`, `ods`.`ods_tidb_readernovel_tidb_userrealtimerecord`.`GroupType` AS `group_type`, `ods`.`ods_tidb_readernovel_tidb_userrealtimerecord`.`JoinDays` AS `join_days`, `ods`.`ods_tidb_readernovel_tidb_userrealtimerecord`.`CanRepeated` AS `can_repeated`, `ods`.`ods_tidb_readernovel_tidb_userrealtimerecord`.`StartTime` AS `start_time`, `ods`.`ods_tidb_readernovel_tidb_userrealtimerecord`.`EndTime` AS `end_time`, `ods`.`ods_tidb_readernovel_tidb_userrealtimerecord`.`CreateTime` AS `create_time`
FROM `ods`.`ods_tidb_readernovel_tidb_userrealtimerecord`
GROUP BY 1, 2, 4, 5, 6, 7, 8, 9, 10, 11, 12);
